import Foundation

struct PIIRedactor {
    private static let patterns: [(label: String, pattern: NSRegularExpression)] = [
        // Email addresses
        ("EMAIL", try! NSRegularExpression(pattern: #"[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}"#)),
        // US phone numbers (various formats)
        ("PHONE", try! NSRegularExpression(pattern: #"(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}"#)),
        // Social Security Numbers
        ("SSN", try! NSRegularExpression(pattern: #"\b\d{3}-\d{2}-\d{4}\b"#)),
        // Credit card numbers (simplified)
        ("CREDIT_CARD", try! NSRegularExpression(pattern: #"\b(?:\d[- ]?){13,16}\b"#))
    ]

    /// Replaces PII patterns with labelled placeholders before sending to Claude.
    static func redact(_ text: String) -> String {
        var result = text
        let nsResult = NSMutableString(string: result)

        for (label, regex) in patterns {
            let range = NSRange(nsResult.length.toRange(), in: (nsResult as String))
            regex.replaceMatches(
                in: nsResult,
                range: NSRange(location: 0, length: nsResult.length),
                withTemplate: "[REDACTED_\(label)]"
            )
        }
        return nsResult as String
    }
}

actor ClaudeService {
    private let proxy: ClaudeProxyClient
    private let systemPrompt: String

    init(proxy: ClaudeProxyClient, systemPrompt: String) {
        self.proxy = proxy
        self.systemPrompt = systemPrompt
    }

    func send(userMessage: String) async throws -> String {
        // 1. Sanitise for injection attempts
        guard case .allowed(let clean) = PromptSanitiser.sanitise(userMessage) else {
            throw ClaudeServiceError.inputBlocked
        }

        // 2. Redact PII so Contact Info is not sent to Anthropic
        let redacted = PIIRedactor.redact(clean)

        // 3. Send via backend proxy (user ID header added by proxy client)
        return try await proxy.send(userMessage: redacted, systemPrompt: systemPrompt)
    }
}

enum ClaudeServiceError: Error {
    case inputBlocked
}

// DataAuditURLProtocol — for use in development builds only.
// Register it with URLSession to intercept outbound requests and log their destinations.

#if DEBUG
import Foundation

final class DataAuditURLProtocol: URLProtocol {
    override class func canInit(with request: URLRequest) -> Bool {
        // Log all HTTPS requests
        return request.url?.scheme == "https"
    }

    override class func canonicalRequest(for request: URLRequest) -> URLRequest {
        return request
    }

    override func startLoading() {
        // Log destination domain and any sensitive headers
        if let host = request.url?.host {
            print("[DataAudit] Outbound request to: \(host)")
        }
        // Forward the request normally
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let data, let response {
                self.client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
                self.client?.urlProtocol(self, didLoad: data)
                self.client?.urlProtocolDidFinishLoading(self)
            } else if let error {
                self.client?.urlProtocol(self, didFailWithError: error)
            }
        }
        task.resume()
    }

    override func stopLoading() {}
}
#endif
